from machine import Pin
import time

# P11 (GPIO 48) 외부 버튼
btn = Pin(48, Pin.IN, Pin.PULL_UP)
prev = btn.value()

while True:
    cur = btn.value()
    if cur != prev:
        time.sleep_ms(20)
        if btn.value() == cur:
            if cur == 0:
                print('press')
            else:
                print('release')
            prev = cur
    time.sleep_ms(5)

